import pytest
from docopt import DocoptExit
from hypothesis import given
from hypothesis import strategies as st

from my.error import CommandNotFound, Error
from my.scripting import (
    STATUS,
    check_available,
    docopt,
    exit_error,
    handle_error,
)


def describe_docopt():
    """docopt()"""

    def it_wraps_docopt(mocker):
        """emballe la fonction docopt()."""
        mock = mocker.patch("my.scripting._docopt")

        docopt("foo")

        mock.assert_called_once_with("foo")

    def it_handles_exception(mocker, capsys):
        """gère les exceptions DocoptExit."""
        mocker.patch(
            "my.scripting._docopt",
            side_effect=DocoptExit("foo"),
        )

        with pytest.raises(SystemExit) as e:
            docopt()

        captured = capsys.readouterr()
        assert captured.err == "foo\n"

        assert e.value.code == STATUS.USAGE


def describe_check_available():
    """check_available()"""

    def it_wraps_check_available(mocker):
        """emballe la fonction check_available()."""
        mock = mocker.patch("my.scripting._check_available")

        check_available("foo")

        mock.assert_called_once_with("foo")

    def it_handles_exception(mocker, capsys):
        """gère les exceptions CommandNotFound."""
        mocker.patch(
            "my.scripting._check_available",
            side_effect=CommandNotFound("foo"),
        )

        with pytest.raises(SystemExit) as e:
            check_available()

        captured = capsys.readouterr()
        assert captured.err == f"erreur: {CommandNotFound.message}: foo.\n"

        assert e.value.code == STATUS.NOT_FOUND


def describe_exit_error():
    """exit_error()"""

    def it_needs_a_message():
        """nécessite qu'un message soit spécifié."""
        with pytest.raises(TypeError):
            exit_error()

    def it_prints_error_message(capsys):
        """affiche le message spécifié sur la sortie d'erreur."""
        with pytest.raises(SystemExit):
            exit_error("foo")

        captured = capsys.readouterr()
        assert captured.err == "erreur: foo.\n"

    @given(status=st.integers(min_value=STATUS.MIN, max_value=STATUS.MAX))
    def it_exits_with_given_status(status):
        """termine le script avec le code de status spécifié."""
        with pytest.raises(SystemExit) as e:
            exit_error("foo", status)

        assert e.value.code == status


def describe_handle_error():
    """handle_error()"""

    @given(message=st.text())
    def it_prints_error_message_from_exception(message, capsys):
        """affiche le message de l'exception sur la sortie d'erreur."""
        e = Error()
        e.message = message

        with pytest.raises(SystemExit):
            handle_error(e)

        captured = capsys.readouterr()

        assert captured.err == f"erreur: {message}.\n"

    @given(status=st.integers(min_value=STATUS.MIN, max_value=STATUS.MAX))
    def it_exits_with_status_from_exception(status):
        """termine le script avec le code de status de l'exception."""
        e = Error()
        e.status = status

        with pytest.raises(SystemExit) as ex:
            handle_error(e)

        assert ex.value.code == status
